// services/chat.service.ts
import { Injectable, inject, OnDestroy } from '@angular/core';
import { BehaviorSubject } from 'rxjs';
import { delay, map, shareReplay } from 'rxjs/operators';
import { RealtimeChannel } from '@supabase/supabase-js';
import { SupabaseService } from './Base/supabase.service';
import { AuthService } from './Base/auth.service';
import { LoadingService } from './Base/loading.service';

export interface ChatConversation {
  id: string;
  restaurant_id: string;
  type: 'group' | 'direct';
  name: string | null;
  created_at: string;
  updated_at: string;
  last_message?: ChatMessage | null;
  other_participant?: any;
}

export interface ChatParticipant {
  id: string;
  conversation_id: string;
  user_id: string;
  joined_at: string;
  left_at: string | null;
  user?: any;
}

export interface ChatMessage {
  id: string;
  conversation_id: string;
  sender_id: string;
  content: string;
  created_at: string;
  updated_at: string;
  sender?: any;
}

@Injectable({ providedIn: 'root' })
export class ChatService implements OnDestroy {
  private supabase = inject(SupabaseService);
  private authService = inject(AuthService);
  private loadingService = inject(LoadingService);

  private messagesSubject = new BehaviorSubject<ChatMessage[]>([]);
  public messages$ = this.messagesSubject.asObservable().pipe(shareReplay(1));

  private conversationsSubject = new BehaviorSubject<ChatConversation[]>([]);
  public conversations$ = this.conversationsSubject.asObservable().pipe(shareReplay(1));

  public activeConversationSubject = new BehaviorSubject<ChatConversation | null>(null);
  public activeConversation$ = this.activeConversationSubject.asObservable();

  private loadingSubject = new BehaviorSubject<boolean>(false);
  public loading$ = this.loadingSubject.asObservable();

  private realtimeChannel: RealtimeChannel | null = null;
  private processedMessageIds = new Set<string>();

  private unreadCountSubject = new BehaviorSubject<Map<string, number>>(new Map());
  public unreadCount$ = this.unreadCountSubject.asObservable();
  private globalRealtimeChannel: RealtimeChannel | null = null;
  private lastReadMap = new Map<string, string>(); 

public totalUnread$ = this.unreadCount$.pipe(
  map(map => Array.from(map.values()).reduce((sum, count) => sum + count, 0)),
  delay(0)  // forza l'emissione nel prossimo ciclo di change detection
);

  constructor() {
this.authService.activeRestaurantId$.subscribe(() => {
  this.unreadCountSubject.next(new Map());
  this.setupGlobalRealtimeSubscription(); // <-- Aggiungi
    });
  }

private incrementUnread(conversationId: string, amount: number = 1, source?: string) {
  console.log(`🔴 incrementUnread da ${source} per ${conversationId} amount ${amount}`);
  const current = this.unreadCountSubject.value;
  const newCount = (current.get(conversationId) || 0) + amount;
  current.set(conversationId, newCount);
  this.unreadCountSubject.next(new Map(current));
}

private resetUnread(conversationId: string) {
  console.log('🟢 resetUnread per', conversationId);
  const current = this.unreadCountSubject.value;
  if (current.has(conversationId)) {
    current.delete(conversationId);
    this.unreadCountSubject.next(new Map(current));
  }
}

  // --- Gestione conversazioni ---
async loadConversations(): Promise<void> {
  const restaurantId = this.authService.getCurrentRestaurantId();
  const currentUserId = this.authService.currentUserValue?.id;
  if (!restaurantId || !currentUserId) {
    this.conversationsSubject.next([]);
    return;
  }

  this.loadingSubject.next(true);
  try {
    // Ottieni gli ID delle conversazioni a cui l'utente partecipa
    const { data: participantData, error: partError } = await this.run<any[]>(
      this.supabase.getSupabaseClient()
        .from('chat_participants')
        .select('conversation_id')
        .eq('user_id', currentUserId)
        .is('left_at', null)
    );
    if (partError) throw partError;

    const conversationIds = participantData?.map(p => p.conversation_id) || [];
    if (conversationIds.length === 0) {
      this.conversationsSubject.next([]);
      this.unreadCountSubject.next(new Map()); // 🟢 azzera anche i non letti
      return;
    }

    // Recupera le conversazioni con partecipanti e ultimo messaggio
    const { data, error } = await this.run<any[]>(
      this.supabase.getSupabaseClient()
        .from('chat_conversations')
        .select(`
          *,
          participants:chat_participants(*),
          last_message:chat_messages(
            id, content, sender_id, created_at
          )
        `)
        .in('id', conversationIds)
        .eq('restaurant_id', restaurantId)
        .order('updated_at', { ascending: false })
    );
    if (error) throw error;

    // Pulisci la mappa dei last_read
    this.lastReadMap.clear();
    const conversations: ChatConversation[] = [];
    const unreadMap = new Map<string, number>(); // 🟢 nuova mappa per i non letti

    for (const item of data || []) {
      const conv: ChatConversation = {
        id: item.id,
        restaurant_id: item.restaurant_id,
        type: item.type,
        name: item.name,
        created_at: item.created_at,
        updated_at: item.updated_at,
        last_message: null,
        other_participant: undefined
      };

      // Ultimo messaggio
      if (item.last_message?.length) {
        const sorted = item.last_message.sort(
          (a: any, b: any) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
        );
        conv.last_message = sorted[0];
      }

      // Last read
      const currentParticipant = item.participants?.find((p: any) => p.user_id === currentUserId);
      let lastReadAt = currentParticipant?.last_read_at;
      if (!lastReadAt) {
        lastReadAt = currentParticipant?.joined_at || item.created_at;
      }
      this.lastReadMap.set(item.id, lastReadAt);

      // Conta messaggi non letti
      const { count, error: countError } = await this.supabase.getSupabaseClient()
        .from('chat_messages')
        .select('id', { count: 'exact', head: true })
        .eq('conversation_id', item.id)
        .gt('created_at', lastReadAt)
        .neq('sender_id', currentUserId);

      if (!countError && count && count > 0) {
        unreadMap.set(item.id, count); // 🟢 assegna direttamente
      }

      // Altro partecipante per chat dirette
      if (conv.type === 'direct') {
        const otherParticipant = item.participants?.find((p: any) => p.user_id !== currentUserId);
        if (otherParticipant) {
          const { data: user, error: userError } = await this.supabase.getSupabaseClient()
            .from('users')
            .select('id, first_name, last_name, avatar_url')
            .eq('id', otherParticipant.user_id)
            .single();

          if (!userError && user) {
            conv.other_participant = user;
          }
        }
      }

      conversations.push(conv);
    }

    this.conversationsSubject.next(conversations);
    this.unreadCountSubject.next(unreadMap); 
  } catch (error) {
    console.error('Error loading conversations:', error);
  } finally {
    this.loadingSubject.next(false);
    await this.setupGlobalRealtimeSubscription();
  }
}

async setActiveConversation(conversation: ChatConversation | null): Promise<void> {
  if (this.activeConversationSubject.value?.id === conversation?.id) return;

  if (this.realtimeChannel) {
    await this.supabase.getSupabaseClient().removeChannel(this.realtimeChannel);
    this.realtimeChannel = null;
  }

  this.activeConversationSubject.next(conversation);

  if (conversation) {
    const userId = this.authService.currentUserValue?.id;
    if (userId) {
      const now = new Date().toISOString();

      // Aggiorna last_read_at nel database
      const { error } = await this.supabase.getSupabaseClient()
        .from('chat_participants')
        .update({ last_read_at: now })
        .eq('conversation_id', conversation.id)
        .eq('user_id', userId);

      if (error) {
        console.error('❌ Errore aggiornamento last_read_at:', error);
      } else {
        // Aggiorna la mappa locale
        this.lastReadMap.set(conversation.id, now);
        // Resetta i non letti per questa conversazione
        this.resetUnread(conversation.id);
      }
    }

    await this.loadMessages(conversation.id);
    this.subscribeToMessages(conversation.id);
  } else {
    this.messagesSubject.next([]);
  }
}

  // --- Gestione messaggi ---
  async loadMessages(conversationId: string): Promise<void> {
    this.loadingSubject.next(true);
    try {
      const { data, error } = await this.run<ChatMessage[]>(
        this.supabase.getSupabaseClient()
          .from('chat_messages')
          .select(`
            *,
            sender:sender_id(id, first_name, last_name, email, avatar_url)
          `)
          .eq('conversation_id', conversationId)
          .order('created_at', { ascending: true })
      );

      if (error) throw error;
      this.messagesSubject.next(data || []);
    } catch (error) {
      console.error('Error loading messages:', error);
    } finally {
      this.loadingSubject.next(false);
    }
  }

async sendMessage(conversationId: string, content: string): Promise<ChatMessage | null> {
  const user = this.authService.currentUserValue;
  if (!user) return null;

  try {
    const { data, error } = await this.run<ChatMessage>(
      this.supabase.getSupabaseClient()
        .from('chat_messages')
        .insert({
          conversation_id: conversationId,
          sender_id: user.id,
          content: content.trim()
        })
        .select(`
          *,
          sender:sender_id(id, first_name, last_name, email, avatar_url)
        `)
        .single()
    );

    if (error) throw error;
    if (!data) return null;

    const currentMessages = this.messagesSubject.value;
    this.messagesSubject.next([...currentMessages, data]);

    // Aggiorna manualmente l'ultimo messaggio nella conversazione locale
    const currentConvs = this.conversationsSubject.value;
    const updatedConvs = currentConvs.map(conv => {
      if (conv.id === conversationId) {
        return { ...conv, last_message: data };
      }
      return conv;
    });
    this.conversationsSubject.next(updatedConvs);

    return data;
  } catch (error) {
    console.error('Error sending message:', error);
    return null;
  }
}

  async updateMessage(messageId: string, newContent: string): Promise<boolean> {
    try {
      const { error } = await this.run(
        this.supabase.getSupabaseClient()
          .from('chat_messages')
          .update({ content: newContent.trim() })
          .eq('id', messageId)
      );
      if (error) throw error;

      const messages = this.messagesSubject.value.map(m =>
        m.id === messageId ? { ...m, content: newContent, updated_at: new Date().toISOString() } : m
      );
      this.messagesSubject.next(messages);
      return true;
    } catch (error) {
      console.error('Error updating message:', error);
      return false;
    }
  }

  async deleteMessage(messageId: string): Promise<boolean> {
    try {
      const { error } = await this.run(
        this.supabase.getSupabaseClient()
          .from('chat_messages')
          .delete()
          .eq('id', messageId)
      );
      if (error) throw error;

      const messages = this.messagesSubject.value.filter(m => m.id !== messageId);
      this.messagesSubject.next(messages);
      return true;
    } catch (error) {
      console.error('Error deleting message:', error);
      return false;
    }
  }

  // --- Realtime subscription ---
  private subscribeToMessages(conversationId: string): void {
    this.realtimeChannel = this.supabase.getSupabaseClient()
      .channel(`messages:${conversationId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'chat_messages',
          filter: `conversation_id=eq.${conversationId}`
        },
        (payload) => {
          this.handleRealtimeMessage(payload);
        }
      )
      .subscribe();
  }

private handleRealtimeMessage(payload: any): void {
  const currentMessages = this.messagesSubject.value;
  const activeId = this.activeConversationSubject.value?.id;
  console.log('📨 Realtime message event:', payload.eventType, payload.new?.conversation_id, 'active:', activeId);

  switch (payload.eventType) {
    case 'INSERT':
      if (!currentMessages.some(m => m.id === payload.new.id)) {
        // Non incrementare qui - lo fa già la subscription globale
        this.loadSenderAndAdd(payload.new);
      }
      break;
    case 'UPDATE':
      this.messagesSubject.next(
        currentMessages.map(m => m.id === payload.new.id ? { ...m, ...payload.new } : m)
      );
      break;
    case 'DELETE':
      this.messagesSubject.next(
        currentMessages.filter(m => m.id !== payload.old.id)
      );
      break;
  }
}


  private async loadSenderAndAdd(message: any): Promise<void> {
    const { data: sender } = await this.supabase.getSupabaseClient()
      .from('users')
      .select('id, first_name, last_name, email, avatar_url')
      .eq('id', message.sender_id)
      .single();
    const fullMessage = { ...message, sender };
    this.messagesSubject.next([...this.messagesSubject.value, fullMessage]);
  }

  // --- Creazione chat private (direct) ---
async createDirectConversation(otherUserId: string): Promise<ChatConversation | null> {
  const restaurantId = this.authService.getCurrentRestaurantId();
  const currentUser = this.authService.currentUserValue;
  if (!restaurantId || !currentUser) return null;

  // Usa la RPC SECURITY DEFINER che gestisce tutto server-side
  const { data, error } = await this.supabase.getSupabaseClient()
    .rpc('create_direct_conversation', {
      p_restaurant_id: restaurantId,
      p_user1: currentUser.id,
      p_user2: otherUserId
    });

  if (error) {
    console.error('❌ Error creating conversation:', error);
    return null;
  }

  const conversation = data as ChatConversation;

  // Arricchisci con dati dell'altro utente
  const { data: otherUser } = await this.supabase.getSupabaseClient()
    .from('users')
    .select('id, first_name, last_name, avatar_url')
    .eq('id', otherUserId)
    .single();

  const enriched: ChatConversation = {
    ...conversation,
    other_participant: otherUser || null,
    last_message: null
  };

  // Aggiorna lista locale solo se non già presente
  const current = this.conversationsSubject.value;
  const alreadyExists = current.some(c => c.id === enriched.id);
  if (!alreadyExists) {
    this.conversationsSubject.next([enriched, ...current]);
  }

  this.setupGlobalRealtimeSubscription();
  return enriched;
}

/**
 * Verifica se un utente è membro di un ristorante (owner o staff accettato)
 */
private async isUserRestaurantMember(userId: string, restaurantId: string): Promise<boolean> {
  try {
    // Controlla se è owner
    const { data: restaurant, error: ownerError } = await this.supabase.getSupabaseClient()
      .from('restaurants')
      .select('owner_id')
      .eq('id', restaurantId)
      .single();

    if (!ownerError && restaurant && restaurant.owner_id === userId) {
      return true;
    }

    // Controlla se è staff accettato
    const { count, error: staffError } = await this.supabase.getSupabaseClient()
      .from('restaurant_staff')
      .select('*', { count: 'exact', head: true })
      .eq('restaurant_id', restaurantId)
      .eq('user_id', userId)
      .eq('invitation_status', 'accepted');

    if (staffError) {
      console.error('Error checking staff status:', staffError);
      return false;
    }

    return (count || 0) > 0;
  } catch (error) {
    console.error('Error in isUserRestaurantMember:', error);
    return false;
  }
}

  // --- Metodo helper per eseguire query con loader ---
  private async run<R>(query: PromiseLike<{ data: R | null; error: any }>): Promise<{ data: R | null; error: any }> {
    this.loadingService.start();
    try {
      return await query;
    } finally {
      this.loadingService.stop();
    }
  }

  ngOnDestroy() {
    if (this.realtimeChannel) {
      this.supabase.getSupabaseClient().removeChannel(this.realtimeChannel);
    }
    this.messagesSubject.complete();
    this.conversationsSubject.complete();
    this.activeConversationSubject.complete();
    this.loadingSubject.complete();
  }

  /**
 * Configura una subscription realtime per ricevere tutti i nuovi messaggi
 * nelle conversazioni a cui l'utente partecipa.
 */
private async setupGlobalRealtimeSubscription() {
  const restaurantId = this.authService.getCurrentRestaurantId();
  if (!restaurantId) return;

  const conversationIds = this.conversationsSubject.value.map(c => c.id);
  if (conversationIds.length === 0) {
    console.log('⚠️ Nessuna conversazione, subscription globale non avviata');
    return;
  }

  if (this.globalRealtimeChannel) {
    console.log('🔄 Rimozione vecchia subscription globale');
    await this.supabase.getSupabaseClient().removeChannel(this.globalRealtimeChannel);
    this.globalRealtimeChannel = null;
  }

  const filter = `conversation_id=in.(${conversationIds.join(',')})`;
  console.log('🔍 Filtro globale:', filter);

  this.globalRealtimeChannel = this.supabase.getSupabaseClient()
    .channel('global-messages')
    .on(
      'postgres_changes',
      {
        event: 'INSERT',
        schema: 'public',
        table: 'chat_messages',
        filter: filter
      },
      (payload) => {
        console.log('📨 Messaggio globale ricevuto:', payload);
        this.handleGlobalMessage(payload);
      }
    )
    .subscribe((status) => {
      console.log('📡 Subscription globale status:', status);
    });
}

private handleGlobalMessage(payload: any) {
  const msgId = payload.new.id;
  
  // Evita di processare lo stesso messaggio più volte
  if (this.processedMessageIds.has(msgId)) {
    console.log('⏭️ Messaggio già processato, salto:', msgId);
    return;
  }
  this.processedMessageIds.add(msgId);
  setTimeout(() => this.processedMessageIds.delete(msgId), 5000);

  const activeId = this.activeConversationSubject.value?.id;
  const msgConvId = payload.new.conversation_id;
  const currentUserId = this.authService.currentUserValue?.id;

  // Ignora i propri messaggi
  if (payload.new.sender_id === currentUserId) return;

  // Se non è la conversazione attiva, controlla se è da considerare non letto
  if (msgConvId !== activeId) {
    const lastRead = this.lastReadMap.get(msgConvId);
    if (!lastRead || new Date(payload.new.created_at) > new Date(lastRead)) {
      this.incrementUnread(msgConvId, 1, 'global');
    }
  }

  // Aggiorna l'ultimo messaggio nella lista conversazioni
  this.updateConversationLastMessage(payload.new);
}


private updateConversationLastMessage(message: any) {
  const conversations = this.conversationsSubject.value;
  const index = conversations.findIndex(c => c.id === message.conversation_id);
  if (index !== -1) {
    const updated = [...conversations];
    updated[index] = { ...updated[index], last_message: message };
    // Sposta la conversazione in cima
    const [moved] = updated.splice(index, 1);
    updated.unshift(moved);
    this.conversationsSubject.next(updated);
  }
}

}